const net = require('net');

const host = '162.241.203.76';  // ex: mysql.seudominio.com ou srvXXX.hostgator.com
const port = 3306;

function testTcp(host, port, timeoutMs = 5000) {
  return new Promise((resolve) => {
    const socket = new net.Socket();
    const start = Date.now();

    socket.setTimeout(timeoutMs);
    socket.once('connect', () => {
      const ms = Date.now() - start;
      socket.destroy();
      resolve({ ok: true, host, port, ms });
    });
    socket.once('timeout', () => {
      socket.destroy();
      resolve({ ok: false, host, port, error: 'timeout' });
    });
    socket.once('error', (err) => {
      resolve({ ok: false, host, port, error: err.code || err.message });
    });

    socket.connect(port, host);
  });
}

const res = await testTcp(host, port);
return [{ json: res }];
